import type {
  ComponentType,
  HTMLAttributeAnchorTarget,
  HTMLAttributes,
  ReactNode,
  SVGProps,
} from "react";
import { X } from "lucide-react";

import { cn } from "@/lib/utils";
import { OdsArrowOutwardIcon } from "./OdsIcons";

export type OdsToastStatus = "info" | "success" | "warning" | "error";

const statusIconClass: Record<OdsToastStatus, string> = {
  info: "text-[var(--fg-brand)]",
  success: "text-[var(--fg-positive)]",
  warning: "text-[var(--fg-warning)]",
  error: "text-[var(--fg-negative)]",
};

interface OdsToastProps extends Omit<HTMLAttributes<HTMLDivElement>, "title"> {
  actionHref?: string;
  actionLabel?: ReactNode;
  actionTarget?: HTMLAttributeAnchorTarget;
  description?: ReactNode;
  onAction?: () => void;
  onClose?: () => void;
  status?: OdsToastStatus;
  title?: ReactNode;
}

function OdsInfoToastIcon(props: SVGProps<SVGSVGElement>) {
  return (
    <svg viewBox="0 0 20 20" fill="none" aria-hidden="true" {...props}>
      <path
        d="M10 1.667C5.4 1.667 1.667 5.4 1.667 10S5.4 18.333 10 18.333 18.333 14.6 18.333 10 14.6 1.667 10 1.667ZM10.833 14.167H9.167v-5h1.666v5ZM10.833 7.5H9.167V5.833h1.666V7.5Z"
        fill="currentColor"
      />
    </svg>
  );
}

function OdsSuccessToastIcon(props: SVGProps<SVGSVGElement>) {
  return (
    <svg viewBox="0 0 20 20" fill="none" aria-hidden="true" {...props}>
      <path
        d="M9.004 12.813 13.652 8.184l-.996-.996-3.652 3.632-1.66-1.64-.996.996 2.656 2.637ZM10 18.333c-4.6 0-8.333-3.733-8.333-8.333S5.4 1.667 10 1.667 18.333 5.4 18.333 10 14.6 18.333 10 18.333Z"
        fill="currentColor"
      />
    </svg>
  );
}

function OdsWarningToastIcon(props: SVGProps<SVGSVGElement>) {
  return (
    <svg viewBox="0 0 20 20" fill="none" aria-hidden="true" {...props}>
      <path
        d="M3.725 17.5h12.55c1.283 0 2.083-1.392 1.442-2.5L11.442 4.158c-.642-1.108-2.242-1.108-2.884 0L2.283 15c-.641 1.108.159 2.5 1.442 2.5ZM10 11.667a.836.836 0 0 1-.833-.834V9.167c0-.459.375-.834.833-.834s.833.375.833.834v1.666c0 .459-.375.834-.833.834ZM10.833 15H9.167v-1.667h1.666V15Z"
        fill="currentColor"
      />
    </svg>
  );
}

function OdsErrorToastIcon(props: SVGProps<SVGSVGElement>) {
  return (
    <svg viewBox="0 0 20 20" fill="none" aria-hidden="true" {...props}>
      <path
        d="M10 1.667C5.392 1.667 1.667 5.392 1.667 10S5.392 18.333 10 18.333 18.333 14.608 18.333 10 14.608 1.667 10 1.667ZM14.167 12.992l-1.175 1.175L10 11.175l-2.992 2.992-1.175-1.175L8.825 10 5.833 7.008l1.175-1.175L10 8.825l2.992-2.992 1.175 1.175L11.175 10l2.992 2.992Z"
        fill="currentColor"
      />
    </svg>
  );
}

const StatusIcon: Record<
  OdsToastStatus,
  ComponentType<SVGProps<SVGSVGElement>>
> = {
  info: OdsInfoToastIcon,
  success: OdsSuccessToastIcon,
  warning: OdsWarningToastIcon,
  error: OdsErrorToastIcon,
};

export function OdsToast({
  actionHref,
  actionLabel,
  actionTarget,
  className,
  description,
  onAction,
  onClose,
  role,
  status = "info",
  title = "Notification",
  ...props
}: OdsToastProps) {
  const Icon = StatusIcon[status];
  const hasAction = Boolean(actionLabel);
  const ariaRole = role ?? (status === "error" ? "alert" : "status");

  const actionContent = hasAction ? (
    <>
      <span className="truncate">{actionLabel}</span>
      <OdsArrowOutwardIcon className="h-4 w-4 shrink-0" />
    </>
  ) : null;

  return (
    <div
      role={ariaRole}
      data-status={status}
      className={cn(
        "flex w-[280px] max-w-full flex-col gap-1 rounded-xl bg-[var(--bg-surface-primary)] p-3 font-medium shadow-popout",
        className
      )}
      {...props}
    >
      <div className="flex h-5 min-w-0 items-center gap-2">
        <Icon className={cn("h-5 w-5 shrink-0", statusIconClass[status])} />
        <div className="min-w-0 flex-1 truncate text-[16px] leading-[120%] text-[var(--fg-base)]">
          {title}
        </div>
        {onClose ? (
          <button
            type="button"
            onClick={onClose}
            className="flex h-5 w-5 shrink-0 items-center justify-center text-[var(--fg-secondary)] transition-colors hover:text-[var(--fg-base)]"
            aria-label="Dismiss notification"
          >
            <X className="h-5 w-5" />
          </button>
        ) : null}
      </div>

      {description ? (
        <div className="min-w-0 truncate text-[12px] leading-[120%] text-[var(--fg-secondary)]">
          {description}
        </div>
      ) : null}

      {hasAction && actionHref ? (
        <a
          href={actionHref}
          target={actionTarget}
          rel={actionTarget === "_blank" ? "noopener noreferrer" : undefined}
          className="inline-flex h-5 min-w-0 w-fit items-center gap-1 text-[16px] leading-[120%] text-[var(--fg-brand)] transition-opacity hover:opacity-90"
        >
          {actionContent}
        </a>
      ) : hasAction && onAction ? (
        <button
          type="button"
          onClick={onAction}
          className="inline-flex h-5 min-w-0 w-fit items-center gap-1 text-[16px] leading-[120%] text-[var(--fg-brand)] transition-opacity hover:opacity-90"
        >
          {actionContent}
        </button>
      ) : hasAction ? (
        <div className="inline-flex h-5 min-w-0 w-fit items-center gap-1 text-[16px] leading-[120%] text-[var(--fg-brand)]">
          {actionContent}
        </div>
      ) : null}
    </div>
  );
}
