"use client";

import { OdsToast, type OdsToastStatus } from "@/components/orderly/OdsToast";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";
import { Toast, ToastProvider, ToastViewport } from "@/components/ui/toast";

function getOdsToastStatus(
  status?: OdsToastStatus,
  variant?: "default" | "destructive" | null
): OdsToastStatus {
  if (status) {
    return status;
  }

  return variant === "destructive" ? "error" : "info";
}

export function Toaster() {
  const { dismiss, toasts } = useToast();

  return (
    <ToastProvider>
      {toasts.map(function ({
        id,
        title,
        description,
        action,
        actionHref,
        actionLabel,
        actionTarget,
        className,
        onAction,
        status,
        variant,
        ...props
      }) {
        return (
          <Toast
            key={id}
            {...props}
            variant={variant}
            className={cn(
              "w-auto self-end justify-start overflow-visible border-0 bg-transparent p-0 pr-0 shadow-none",
              className
            )}
          >
            <OdsToast
              status={getOdsToastStatus(status, variant)}
              title={title}
              description={description}
              actionLabel={actionLabel}
              actionHref={actionHref}
              actionTarget={actionTarget}
              onAction={onAction}
              onClose={() => dismiss(id)}
            />
            {action}
          </Toast>
        );
      })}
      <ToastViewport />
    </ToastProvider>
  );
}
